#!/usr/bin/env node
/*
 * generate-dataview.js — Dataview-equivalent tables + charts for Gnosis.
 *
 * Reads every content/**\/*.md (except generated index pages themselves),
 * indexes frontmatter + wiki-link references, and emits:
 *   content/dashboard.md
 *   content/{people,companies,sources,concepts}/index.md
 *
 * All generated files start with an AUTO-GENERATED banner so hand-edits are
 * discouraged. Idempotent — re-run overwrites.
 */

const fs = require("node:fs")
const path = require("node:path")
const matter = require("gray-matter")
const {
  donutChart,
  barChart,
  tagCloud,
  timelineBar,
  escapeHtml,
  statsStrip,
  chartFromMdTable,
  cleanLabel,
} = require("./lib/charts.cjs")

const WIDGET_TOP_START = "<!-- GNOSIS:WIDGET:TOP:START -->"
const WIDGET_TOP_END = "<!-- GNOSIS:WIDGET:TOP:END -->"
const WIDGET_BOTTOM_START = "<!-- GNOSIS:WIDGET:BOTTOM:START -->"
const WIDGET_BOTTOM_END = "<!-- GNOSIS:WIDGET:BOTTOM:END -->"
const TABLE_CHART_START = "<!-- GNOSIS:TABLECHART:START -->"
const TABLE_CHART_END = "<!-- GNOSIS:TABLECHART:END -->"

const ROOT = path.resolve(__dirname, "..")
const CONTENT = path.join(ROOT, "content")

const GENERATED_SLUGS = new Set([
  "dashboard",
  "people/index",
  "companies/index",
  "sources/index",
  "concepts/index",
])

const BANNER = "<!-- AUTO-GENERATED by scripts/generate-dataview.js. Do not edit by hand; run `npm run build:dataview`. -->"

function walk(dir, acc = []) {
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name)
    if (entry.isDirectory()) walk(full, acc)
    else if (entry.isFile() && entry.name.endsWith(".md")) acc.push(full)
  }
  return acc
}

function slugFor(fullPath) {
  const rel = path.relative(CONTENT, fullPath)
  return rel.replace(/\.md$/, "").split(path.sep).join("/")
}

function extractWikiLinks(body) {
  const links = new Set()
  const re = /\[\[([^\]|#]+?)(?:[|#][^\]]*)?\]\]/g
  let m
  while ((m = re.exec(body))) {
    links.add(m[1].trim())
  }
  return [...links]
}

function resolveLinkTarget(target, allPages) {
  // target may be bare ("phani-sama"), subpath ("people/phani-sama"), or prefixed alias.
  const normalized = target.toLowerCase().replace(/\s+/g, "-")
  for (const p of allPages) {
    if (p.slug === normalized) return p
    if (p.slug.endsWith("/" + normalized)) return p
    if (p.basename === normalized) return p
  }
  return null
}

function loadPages() {
  return walk(CONTENT)
    .map((fullPath) => {
      const slug = slugFor(fullPath)
      if (GENERATED_SLUGS.has(slug)) return null
      const raw = fs.readFileSync(fullPath, "utf8")
      const { data, content } = matter(raw)
      return {
        slug,
        basename: slug.split("/").pop(),
        fullPath,
        frontmatter: data,
        body: content,
        type: data.type ?? (slug.includes("/") ? slug.split("/")[0].replace(/s$/, "") : "other"),
        tags: Array.isArray(data.tags) ? data.tags : [],
        title: data.title ?? extractTitle(content) ?? slug,
        created: data.created ?? null,
        updated: data.updated ?? null,
        sources: Array.isArray(data.sources) ? data.sources : [],
        outLinks: extractWikiLinks(content),
      }
    })
    .filter(Boolean)
}

function extractTitle(body) {
  const m = body.match(/^#\s+(.+?)\s*$/m)
  return m ? m[1].trim() : null
}

function pageLink(page, fromSlug) {
  // Relative link from fromSlug to page.slug
  const fromDepth = fromSlug.split("/").length - 1
  const prefix = "../".repeat(fromDepth)
  return `[${escapeHtml(page.title)}](${prefix}${page.slug})`
}

function formatDate(d) {
  if (!d) return ""
  if (d instanceof Date) return d.toISOString().slice(0, 10)
  return String(d).slice(0, 10)
}

function monthOf(d) {
  const s = formatDate(d)
  return s ? s.slice(0, 7) : null
}

function writeGenerated(relPath, title, bodyMd) {
  const full = path.join(CONTENT, relPath)
  fs.mkdirSync(path.dirname(full), { recursive: true })
  const fm = `---\ntitle: "${title}"\n---\n\n${BANNER}\n\n${bodyMd.trim()}\n`
  fs.writeFileSync(full, fm, "utf8")
  return relPath
}

function buildIndex(pages) {
  const byType = new Map()
  const byTag = new Map()
  const byMonth = new Map()
  const citationsBySource = new Map()

  for (const p of pages) {
    if (!byType.has(p.type)) byType.set(p.type, [])
    byType.get(p.type).push(p)

    for (const tag of p.tags) {
      const entry = byTag.get(tag) ?? { count: 0, types: new Map() }
      entry.count += 1
      entry.types.set(p.type, (entry.types.get(p.type) ?? 0) + 1)
      byTag.set(tag, entry)
    }

    const month = monthOf(p.created)
    if (month) {
      if (!byMonth.has(month)) byMonth.set(month, new Map())
      const bucket = byMonth.get(month)
      bucket.set(p.type, (bucket.get(p.type) ?? 0) + 1)
    }

    for (const src of p.sources) {
      const key = String(src)
      citationsBySource.set(key, (citationsBySource.get(key) ?? 0) + 1)
    }
  }

  // Dominant type per tag
  const tagCounts = new Map()
  byTag.forEach(({ count, types }, tag) => {
    let dominantType = "other"
    let max = 0
    types.forEach((v, t) => {
      if (v > max) {
        max = v
        dominantType = t
      }
    })
    tagCounts.set(tag, { count, dominantType })
  })

  return { byType, byTag, byMonth, citationsBySource, tagCounts }
}

// ---------- Page builders ----------

function buildDashboard(pages, idx) {
  const slug = "dashboard"
  const typeRows = [...idx.byType.entries()]
    .map(([type, ps]) => ({ label: type, value: ps.length, type }))
    .sort((a, b) => b.value - a.value)

  // Dedupe by basename — different raw paths for the same source should collapse.
  const citationsByBasename = new Map()
  for (const [src, count] of idx.citationsBySource.entries()) {
    const name = path.basename(String(src)).replace(/\.(md|pdf|txt)$/i, "")
    citationsByBasename.set(name, (citationsByBasename.get(name) ?? 0) + count)
  }
  const sourceRows = [...citationsByBasename.entries()]
    .map(([name, count]) => {
      const page = pages.find(
        (p) => p.basename === name || p.slug === `sources/${name}` || p.slug === `entities/${name}`,
      )
      return {
        label: page ? page.title : name,
        value: count,
        type: "source",
        slug: page?.slug,
      }
    })
    .filter((r) => r.label !== "semrush-aivi-shortlink")
    .sort((a, b) => b.value - a.value)
    .slice(0, 10)

  const recent = [...pages]
    .filter((p) => p.created)
    .sort((a, b) => String(b.created).localeCompare(String(a.created)))
    .slice(0, 8)

  const recentTable =
    "| Page | Type | Created |\n|------|------|---------|\n" +
    recent
      .map((p) => `| ${pageLink(p, slug)} | ${p.type} | ${formatDate(p.created)} |`)
      .join("\n")

  const sourceCitedByTable =
    "| Source | Pages citing it |\n|--------|-----------------|\n" +
    sourceRows
      .map(
        (r) =>
          `| ${r.slug ? `[${escapeHtml(r.label)}](${r.slug})` : escapeHtml(r.label)} | ${r.value} |`,
      )
      .join("\n")

  const md = `# Gnosis Dashboard

Auto-generated view of everything in the wiki — computed from page frontmatter on every build.

## Wiki at a glance

${donutChart(typeRows)}

## Most-cited sources

Which raw documents power the most wiki pages? Evidence of the **compounding** thesis: the same handful of sources keep earning new citations as the wiki grows.

${barChart(sourceRows.map((r) => ({ label: r.label, value: r.value, type: "source" })))}

${sourceCitedByTable}

## Tag cloud

Top 30 tags, sized by frequency and colored by dominant page type.

${tagCloud(idx.tagCounts)}

## Ingest timeline

Pages created per month, stacked by type.

${timelineBar(idx.byMonth)}

## Recent additions

${recentTable}

## Browse by type

${[...idx.byType.entries()]
  .sort((a, b) => b[1].length - a[1].length)
  .map(([t, ps]) => {
    const pluralMap = { person: "people", company: "companies", source: "sources", concept: "concepts", entity: "entities", project: "projects" }
    const folder = pluralMap[t]
    const label = `**${t}** (${ps.length})`
    return folder ? `- [${label}](${folder}/index)` : `- ${label}`
  })
  .join("\n")}
`
  return writeGenerated(`${slug}.md`, "Dashboard", md)
}

function buildPeopleIndex(pages, idx) {
  const slug = "people/index"
  const people = (idx.byType.get("person") ?? []).sort((a, b) =>
    a.title.localeCompare(b.title),
  )

  const rows = people.map((p) => {
    const fm = p.frontmatter
    const company = fm.company ? String(fm.company).replace(/\[\[|\]\]/g, "") : ""
    const companyLink = company
      ? `[${escapeHtml(company)}](../companies/${company.toLowerCase().replace(/\s+/g, "-")})`
      : ""
    const sharedCount = p.outLinks.length
    return `| [${escapeHtml(p.title)}](${p.basename}) | ${escapeHtml(fm.role ?? "")} | ${companyLink} | ${escapeHtml(fm["based-in"] ?? "")} | ${sharedCount} |`
  })

  const md = `# People

${people.length} people in Siva's network, computed live from \`wiki/people/*.md\` frontmatter.

| Name | Role | Company | Based in | Outbound links |
|------|------|---------|----------|----------------|
${rows.join("\n")}

> Click a name to open the person's wiki page. **Outbound links** is the number of \`[[wiki-links]]\` the page contains — a rough density measure of that person's position in the graph.
`
  return writeGenerated("people/index.md", "People", md)
}

function buildCompaniesIndex(pages, idx) {
  const companies = (idx.byType.get("company") ?? []).sort((a, b) =>
    a.title.localeCompare(b.title),
  )

  const rows = companies.map((p) => {
    const fm = p.frontmatter
    const website = fm.website ? `[${new URL(fm.website).hostname}](${fm.website})` : ""
    const primaryTag = (p.tags[0] ?? "").toString()
    const inbound = pages.filter((other) =>
      other.outLinks.some((l) => l === p.basename || l === p.slug || l.endsWith("/" + p.basename)),
    ).length
    return `| [${escapeHtml(p.title)}](${p.basename}) | ${escapeHtml(primaryTag)} | ${inbound} | ${website} |`
  })

  const md = `# Companies and institutions

${companies.length} organizations tracked, computed live from \`wiki/companies/*.md\` frontmatter.

| Name | Primary tag | Inbound links | Website |
|------|-------------|---------------|---------|
${rows.join("\n")}

> **Inbound links** counts how many other wiki pages reference this company via \`[[wiki-links]]\` — higher means more central to the graph.
`
  return writeGenerated("companies/index.md", "Companies", md)
}

function buildSourcesIndex(pages, idx) {
  const sources = (idx.byType.get("source") ?? []).sort((a, b) =>
    String(b.created ?? "").localeCompare(String(a.created ?? "")),
  )

  const rows = sources.map((p) => {
    const fm = p.frontmatter
    const authors = Array.isArray(fm.authors) ? fm.authors.join(", ") : fm.authors ?? ""
    const published = formatDate(fm.published ?? fm.created)
    const citedBy = pages.filter((other) =>
      other.sources.some((s) => {
        const name = path.basename(String(s)).replace(/\.(md|pdf|txt)$/i, "")
        return name === p.basename || String(s).includes(p.basename)
      }),
    ).length
    return `| [${escapeHtml(p.title)}](${p.basename}) | ${escapeHtml(authors)} | ${published} | ${citedBy} |`
  })

  const md = `# Sources

${sources.length} raw sources ingested, computed live from \`wiki/sources/*.md\` frontmatter.

| Title | Authors | Published | Cited by |
|-------|---------|-----------|----------|
${rows.join("\n")}

> **Cited by** counts how many non-source wiki pages list this source in their \`sources:\` frontmatter. Higher = source is earning its keep.
`
  return writeGenerated("sources/index.md", "Sources", md)
}

function buildConceptsIndex(pages, idx) {
  const concepts = (idx.byType.get("concept") ?? []).sort((a, b) =>
    a.title.localeCompare(b.title),
  )

  const rows = concepts.map((p) => {
    const tagList = p.tags.slice(0, 3).map((t) => `\`${escapeHtml(t)}\``).join(" ")
    return `| [${escapeHtml(p.title)}](${p.basename}) | ${tagList} | ${p.sources.length} | ${formatDate(p.updated)} |`
  })

  const md = `# Concepts

${concepts.length} concepts indexed, computed live from \`wiki/concepts/*.md\` frontmatter.

| Name | Tags | Source count | Last updated |
|------|------|--------------|--------------|
${rows.join("\n")}
`
  return writeGenerated("concepts/index.md", "Concepts", md)
}

// ---------- Per-page widgets ----------

// Remove prior widget blocks so re-runs are idempotent.
function stripWidgets(body) {
  return body
    .replace(new RegExp(`${WIDGET_TOP_START}[\\s\\S]*?${WIDGET_TOP_END}\\n?`, "g"), "")
    .replace(new RegExp(`${WIDGET_BOTTOM_START}[\\s\\S]*?${WIDGET_BOTTOM_END}\\n?`, "g"), "")
    .replace(new RegExp(`${TABLE_CHART_START}[\\s\\S]*?${TABLE_CHART_END}\\n?`, "g"), "")
}

function buildBacklinkIndex(pages) {
  const byTarget = new Map()
  for (const p of pages) {
    for (const link of p.outLinks) {
      const key = link.toLowerCase()
      if (!byTarget.has(key)) byTarget.set(key, [])
      byTarget.get(key).push(p)
    }
  }
  return byTarget
}

function backlinksFor(page, backlinkIdx) {
  const keys = new Set([page.basename, page.slug, page.title?.toLowerCase()])
  const seen = new Set()
  const out = []
  for (const k of keys) {
    if (!k) continue
    for (const p of backlinkIdx.get(k.toLowerCase()) ?? []) {
      if (p.slug === page.slug) continue
      if (seen.has(p.slug)) continue
      seen.add(p.slug)
      out.push(p)
    }
  }
  return out
}

// Top widget: stats strip.
function topWidget(page, backlinks) {
  const strip = statsStrip({
    type: page.type,
    tags: page.tags,
    outbound: page.outLinks.length,
    backlinks: backlinks.length,
    sources: page.sources.length,
    updated: page.updated ?? page.created ?? "",
  })
  return `${WIDGET_TOP_START}\n${strip}\n${WIDGET_TOP_END}\n`
}

// Inject auto-charts after every numeric markdown table in the body.
function injectTableCharts(body) {
  // Find markdown tables by detecting header+separator+rows blocks.
  const lines = body.split("\n")
  const blocks = []
  let i = 0
  while (i < lines.length) {
    if (/^\|.+\|\s*$/.test(lines[i]) && i + 1 < lines.length && /^\|[\s\-:|]+\|\s*$/.test(lines[i + 1])) {
      const start = i
      let end = i + 2
      while (end < lines.length && /^\|.+\|\s*$/.test(lines[end])) end++
      blocks.push({ start, end })
      i = end
    } else {
      i++
    }
  }
  if (!blocks.length) return body
  // Process in reverse so indices stay valid.
  for (let b = blocks.length - 1; b >= 0; b--) {
    const block = blocks[b]
    const tableText = lines.slice(block.start, block.end).join("\n")
    // Skip tables that already have a chart marker right after.
    const after = lines[block.end] ?? ""
    if (after.includes(TABLE_CHART_START)) continue
    const chart = chartFromMdTable(tableText)
    if (!chart) continue
    const wrapped = `${TABLE_CHART_START}\n${chart.trim()}\n${TABLE_CHART_END}`
    lines.splice(block.end, 0, wrapped)
  }
  return lines.join("\n")
}

function typeSpecificWidget(page, idx, pages, backlinks) {
  const parts = []

  if (page.type === "source") {
    // Bar chart: pages citing this source, grouped by type.
    const citers = pages.filter((p) =>
      p.sources.some((s) => {
        const name = path.basename(String(s)).replace(/\.(md|pdf|txt)$/i, "")
        return name === page.basename || String(s).includes(page.basename)
      }),
    )
    if (citers.length) {
      const byType = new Map()
      for (const c of citers) byType.set(c.type, (byType.get(c.type) ?? 0) + 1)
      const rows = [...byType.entries()]
        .map(([type, count]) => ({ label: type, value: count, type }))
        .sort((a, b) => b.value - a.value)
      parts.push(`### Pages citing this source\n\n${barChart(rows, { width: 520 })}\n\n**${citers.length} pages** cite this source across ${byType.size} types.`)
    }
  }

  if (page.type === "concept" || page.type === "entity") {
    // Related pages by tag overlap.
    const related = pages
      .filter((p) => p.slug !== page.slug && p.tags.length)
      .map((p) => {
        const overlap = p.tags.filter((t) => page.tags.includes(t)).length
        return { page: p, overlap }
      })
      .filter((r) => r.overlap > 0)
      .sort((a, b) => b.overlap - a.overlap)
      .slice(0, 8)
    if (related.length) {
      const rows = related.map((r) => ({ label: r.page.title, value: r.overlap, type: r.page.type }))
      parts.push(`### Related by shared tags\n\n${barChart(rows, { width: 520 })}\n\n*X-axis: number of tags this page shares with each related page.*`)
    }
  }

  if (page.type === "person") {
    // Stat list: companies linked, other people linked, top 5 connected pages by backlink density.
    const companyLinks = page.outLinks
      .map((l) => pages.find((p) => p.basename === l && p.type === "company"))
      .filter(Boolean)
    const peopleLinks = page.outLinks
      .map((l) => pages.find((p) => p.basename === l && p.type === "person"))
      .filter(Boolean)
    if (companyLinks.length) {
      const rows = companyLinks
        .slice(0, 10)
        .map((p) => ({ label: p.title, value: 1, type: "company" }))
      // Single-value bars aren't useful; render as styled list instead.
      const items = companyLinks
        .map(
          (p) =>
            `<li style="display:inline-block;margin:.25rem .4rem .25rem 0;padding:.2rem .65rem;background:${cleanLabel ? "" : ""}var(--lightgray,#e2e8f0);border-radius:999px"><a href="../companies/${p.basename}" style="color:inherit;text-decoration:none">${escapeHtml(p.title)}</a></li>`,
        )
        .join("")
      parts.push(`### Companies linked from this profile\n\n<ul style="list-style:none;padding:0;margin:.5rem 0">${items}</ul>`)
    }
    if (peopleLinks.length) {
      parts.push(
        `### People linked from this profile\n\n` +
          peopleLinks.map((p) => `- [${p.title}](${p.basename})`).join("\n"),
      )
    }
  }

  if (page.type === "company") {
    // Bar chart: which people are linked here (backlinks from people/ pages).
    const people = backlinks.filter((p) => p.type === "person")
    if (people.length) {
      const rows = people.map((p) => ({ label: p.title, value: 1, type: "person" }))
      parts.push(`### People linked to this company\n\n${people.map((p) => `- [${p.title}](../people/${p.basename})`).join("\n")}`)
    }
    // Related companies by shared tags.
    const related = pages
      .filter((p) => p.type === "company" && p.slug !== page.slug && p.tags.length)
      .map((p) => ({ page: p, overlap: p.tags.filter((t) => page.tags.includes(t)).length }))
      .filter((r) => r.overlap > 0)
      .sort((a, b) => b.overlap - a.overlap)
      .slice(0, 6)
    if (related.length) {
      const rows = related.map((r) => ({ label: r.page.title, value: r.overlap, type: "company" }))
      parts.push(`### Similar companies (by shared tags)\n\n${barChart(rows, { width: 520 })}`)
    }
  }

  if (!parts.length && backlinks.length) {
    // Universal fallback: "Cited by" list.
    parts.push(
      `### Pages referencing this one\n\n` +
        backlinks
          .slice(0, 8)
          .map((p) => `- [${p.title}](../${p.type === "concept" ? "concepts" : p.type === "person" ? "people" : p.type === "company" ? "companies" : p.type === "source" ? "sources" : p.type === "entity" ? "entities" : "projects"}/${p.basename}) (${p.type})`)
          .join("\n"),
    )
  }

  if (!parts.length) return ""
  const body = parts.join("\n\n")
  return `${WIDGET_BOTTOM_START}\n## Gnosis context\n\n${body}\n${WIDGET_BOTTOM_END}\n`
}

function injectWidgetsIntoFile(fullPath, page, idx, pages, backlinks) {
  const raw = fs.readFileSync(fullPath, "utf8")
  const { data, content } = matter(raw)
  let body = stripWidgets(content)

  // 1. Top stats strip — insert after first H1 (or at top of body if no H1).
  const top = topWidget(page, backlinks)
  const h1Match = body.match(/^(#\s+.+\n)/m)
  if (h1Match) {
    body = body.replace(h1Match[1], `${h1Match[1]}\n${top}\n`)
  } else {
    body = `${top}\n${body}`
  }

  // 2. Auto-chart every numeric table.
  body = injectTableCharts(body)

  // 3. Type-specific bottom widget — insert before final `## Links` section if present.
  const bottom = typeSpecificWidget(page, idx, pages, backlinks)
  if (bottom) {
    const linksMatch = body.match(/\n(## Links\s*\n)/)
    if (linksMatch) {
      body = body.replace(linksMatch[0], `\n${bottom}\n${linksMatch[1]}`)
    } else {
      body = `${body.trimEnd()}\n\n${bottom}`
    }
  }

  fs.writeFileSync(fullPath, matter.stringify(body, data), "utf8")
}

function processAllPages(pages, idx) {
  const backlinkIdx = buildBacklinkIndex(pages)
  let modified = 0
  for (const page of pages) {
    const backlinks = backlinksFor(page, backlinkIdx)
    injectWidgetsIntoFile(page.fullPath, page, idx, pages, backlinks)
    modified += 1
  }
  return modified
}

// ---------- Main ----------

function main() {
  const pages = loadPages()
  const idx = buildIndex(pages)
  const written = []
  written.push(buildDashboard(pages, idx))
  written.push(buildPeopleIndex(pages, idx))
  written.push(buildCompaniesIndex(pages, idx))
  written.push(buildSourcesIndex(pages, idx))
  written.push(buildConceptsIndex(pages, idx))

  const injected = processAllPages(pages, idx)

  console.log(`  Indexed ${pages.length} pages across ${idx.byType.size} types.`)
  console.log(`  Types: ${[...idx.byType.entries()].map(([t, ps]) => `${t}=${ps.length}`).join(", ")}`)
  console.log(`  Tags: ${idx.byTag.size} unique, ${idx.citationsBySource.size} cited sources.`)
  console.log(`  Wrote ${written.length} aggregation files:`)
  for (const w of written) console.log(`    - content/${w}`)
  console.log(`  Injected widgets into ${injected} content pages.`)
}

try {
  main()
} catch (err) {
  console.error("generate-dataview.js failed:", err)
  process.exit(1)
}
